<body>
<textarea id="data-source" style="display:none;">$1</textarea>
<div class="terminal-container">
    <div class="top-bar"></div>
    <div class="header">
        <div class="guild-badge">
            <div class="guild-logo">Tu</div>
            <div class="guild-name">Bảng trạng thái</div>
        </div>
        <div class="time-display" id="env-status"></div>
    </div>
    <div class="content-grid">
        <div class="status-panel">
            <div class="avatar-wrapper">
                <div class="avatar-frame"><div class="user_avatar"></div></div>
                <div class="rank-tag"></div>
            </div>
            <div class="stat-group">
                <div class="stat-row"><div class="stat-label"><span>Sinh mệnh</span><span id="hp-value"></span></div><div class="progress-bg"><div class="progress-fill fill-hp" id="hp-bar"></div></div></div>
                <div class="stat-row"><div class="stat-label"><span>Tinh huyết</span><span id="blood-value"></span></div><div class="progress-bg"><div class="progress-fill fill-hp" id="blood-bar"></div></div></div>
                <div class="stat-row"><div class="stat-label"><span>Linh lực</span><span id="mp-value"></span></div><div class="progress-bg"><div class="progress-fill fill-mp" id="mp-bar"></div></div></div>
                <div class="stat-row"><div class="stat-label"><span>Tu vi</span><span id="exp-value"></span></div><div class="progress-bg"><div class="progress-fill fill-exp" id="exp-bar"></div></div></div>
                <div class="stat-row"><div class="stat-label"><span>Thần thức</span><span id="san-value" class="rare-text" style="font-weight:normal; text-align:right;"></span></div></div>
                <div class="stat-row"><div class="stat-label"><span>Khí vận</span><span id="luck-value" class="rare-text" style="font-weight:normal; text-align:right;"></span></div></div>
                <div class="stat-row"><div class="stat-label"><span>Linh căn</span><span id="spirit-root-value" class="rare-text" style="font-weight:normal; text-align:right;"></span></div></div>
                <!-- 新增宗门显示 -->
                <div class="stat-row"><div class="stat-label"><span>Tông môn</span><span id="clan-value" class="rare-text" style="font-weight:normal; text-align:right;">Không</span></div></div>
                <div class="stat-row"><div class="stat-label"><span>Trạng thái</span><span id="status-effects" class="rare-text" style="font-weight:normal; text-align:right;">Không</span></div></div>
            </div>
        </div>
        <div class="main-panel">
            <div class="nav-tabs">
                <button class="tab-btn active" onclick="switchTab(event, 'dashboard')">Tổng quan</button>
                <button class="tab-btn" onclick="switchTab(event, 'skills')">Công pháp</button>
                <button class="tab-btn" onclick="switchTab(event, 'partners')">Đạo lữ</button>
                <button class="tab-btn" onclick="switchTab(event, 'npcs')">Nhân vật</button>
                <button class="tab-btn" onclick="switchTab(event, 'quests')">Cơ duyên</button>
                <button class="tab-btn" onclick="switchTab(event, 'database')">Nhật ký</button>
            </div>
            <div id="tab-dashboard" class="tab-content" style="display: block;"></div>
            <div id="tab-skills" class="tab-content" style="display: none;"></div>
            <div id="tab-partners" class="tab-content" style="display: none;"></div>
            <div id="tab-npcs" class="tab-content" style="display: none;"></div>
            <div id="tab-quests" class="tab-content" style="display: none;"></div>
