        </div>
    </div>
    <div class="fairy-container" id="fairy-guide">
        <div class="fairy-bubble" style="opacity: 0; transform: translateY(10px); pointer-events: none;"><span id="fairy-text">...</span></div>
        <div class="fairy-avatar" title="Nhấn vào Khí Linh để xem gợi ý "></div>
    </div>
</div>

<script>
    let globalXmlData = null;

    function switchTab(event, tabId) {
        const button = event.currentTarget;
        const panel = button.closest('.main-panel');
        if (!panel) return;
        panel.querySelectorAll('.tab-btn').forEach(btn => btn.classList.remove('active'));
        panel.querySelectorAll('.tab-content').forEach(p => p.style.display = 'none');
        const tabToShow = document.getElementById('tab-' + tabId);
        if (tabToShow) {
            tabToShow.style.display = 'block';
        }
        button.classList.add('active');
    }

    const fairyGuide = {
        element: document.getElementById('fairy-guide'),
        textElement: document.getElementById('fairy-text'),
        toggleAndShowMessage() {
            const bubble = this.element.querySelector('.fairy-bubble');
            const isVisible = bubble.style.opacity === '1';

            if (isVisible) {
                bubble.style.opacity = '0';
                bubble.style.transform = 'translateY(10px)';
                bubble.style.pointerEvents = 'none';
            } else {
                if (!globalXmlData) return;

                const getMessagesFromXML = (category) => {
                    let nodes = globalXmlData.querySelectorAll(`fairy_messages > ${category} > message`);
                    if (nodes.length === 0 && category !== 'generic') {
                        nodes = globalXmlData.querySelectorAll('fairy_messages > generic > message');
                    }
                    if (nodes.length === 0) {
                        return ["Đạo hữu, nơi này thiên cơ hỗn loạn, không thể dò xét..."];
                    }
                    return Array.from(nodes).map(node => node.textContent.trim());
                };

                const get = (tag) => globalXmlData.querySelector(tag)?.textContent.trim() || '0';
                const stats = {
                    hp: parseFloat(get('hp_current')), hpMax: parseFloat(get('hp_max')) || 100, san: parseFloat(get('san_current')), sanMax: parseFloat(get('san_max')) || 100, mp: parseFloat(get('mp_current')), mpMax: parseFloat(get('mp_max')) || 100
                };

                let messageCategory;
                if (stats.hp / stats.hpMax < 0.3) messageCategory = 'lowHealth';
                else if (stats.san / stats.sanMax < 0.4) messageCategory = 'lowSanity';
                else if (stats.mp / stats.mpMax < 0.2) messageCategory = 'lowMana';
                else messageCategory = 'generic';

                const pool = getMessagesFromXML(messageCategory);
                this.textElement.textContent = pool[Math.floor(Math.random() * pool.length)];
                bubble.style.opacity = '1';
                bubble.style.transform = 'translateY(0)';
                bubble.style.pointerEvents = 'auto';
            }
        },
        init() { this.element.querySelector('.fairy-avatar').addEventListener('click', () => this.toggleAndShowMessage()); }
    };

    document.addEventListener('DOMContentLoaded', () => {
        const dataSource = document.getElementById('data-source');
        fairyGuide.init();
        if (dataSource && dataSource.value.trim()) {
            const parser = new DOMParser();
            // 这是关键的修正点：将 "text/xml" 修改为 "text/html"
            globalXmlData = parser.parseFromString(dataSource.value, "text/html");
            renderUI(globalXmlData);
        }
        const firstTab = document.querySelector('.tab-btn');
        if (firstTab) {
            firstTab.click();
        }
    });

    function renderUI(doc) {
        const avatarUrl = window.parent.document.querySelector('#user_avatar_image')?.src;
        const userAvatarElement = document.querySelector('.user_avatar');
        if (userAvatarElement && avatarUrl) {
            userAvatarElement.style.backgroundImage = `url('${avatarUrl}')`;
        }

        const dataRoot = doc.querySelector('data_block') || doc;
        const getGlobal = (tag) => dataRoot.querySelector(tag)?.textContent.trim() || '';
        const getGlobalHtml = (tag) => {
            const node = dataRoot.querySelector(tag);
            if (!node) return '';
            if (node.firstChild && node.firstChild.nodeType === Node.CDATA_SECTION_NODE) {
                return node.firstChild.textContent.trim();
            }
            // 使用 innerHTML 替代 textContent 来保留HTML标签
            return node.innerHTML.trim();
        };
        const setTxt = (sel, val) => { const el = document.querySelector(sel); if (el) el.textContent = val; };
        const setHtml = (sel, val) => { const el = document.querySelector(sel); if (el) el.innerHTML = val; };
        const updateStat = (name, current, max) => {
            current = parseFloat(current) || 0; max = parseFloat(max) || 100;
            const percentage = max > 0 ? (current / max) * 100 : 0;
            const valueEl = document.getElementById(`${name}-value`);
            const barEl = document.getElementById(`${name}-bar`);
            if (valueEl) valueEl.textContent = `${Math.round(current)}/${Math.round(max)}`;
            if (barEl) barEl.style.width = `${percentage}%`;
        };
        setTxt('#env-status', " ⚜️ {{user}}");
        setTxt('.rank-tag', getGlobal('rank'));
        updateStat('hp', getGlobal('hp_current'), getGlobal('hp_max'));
        updateStat('blood', getGlobal('blood_current'), getGlobal('blood_max'));
        updateStat('mp', getGlobal('mp_current'), getGlobal('mp_max'));
        updateStat('exp', getGlobal('exp_current'), getGlobal('exp_max'));
        setTxt('#san-value', getGlobal('san_status') || 'Không');
        setTxt('#luck-value', getGlobal('luck_status') || 'Không');
        setTxt('#spirit-root-value', getGlobal('spirit_root_status') || 'Không');
        setTxt('#clan-value', getGlobal('clan') || 'Không');
        setHtml('#status-effects', getGlobal('status_effects') || 'Bình thường');
        setHtml('#tab-dashboard', `
            <div class="info-card">
                <div class="info-title"><span>Vị trí hiện tại</span><span>📍</span></div>
                <div class="info-text">${getGlobalHtml('location')}</div>
            </div>
            <div class="info-card" style="border-color: var(--accent-blood);">
                <div class="info-title" style="color: var(--accent-blood);"><span>Thiên cơ thôi diễn</span><span>⚠️</span></div>
                <div class="info-text">
                    ${getGlobalHtml('time')}<br>
                    Mức độ nguy hiểm: ${getGlobalHtml('threat_level')}
                </div>
            </div>
            <div class="info-card">
                <div class="info-title"><span>Túi trữ vật</span><span>🎒</span></div>
                <div class="info-text">${getGlobalHtml('inventory')}</div>
            </div>`);
        setHtml('#tab-database > p', getGlobalHtml('log'));
        const renderList = (selector, containerSel, factory) => {
            const items = Array.from(dataRoot.querySelectorAll(selector));
            setHtml(containerSel, items.length > 0 ? items.map(factory).join('') : '<p>Tạm không có ghi chép.</p>');
        };
        renderList('skills > skill', '#tab-skills', item => {
            const get = (tag) => item.querySelector(tag)?.textContent.trim() || '';
            const getHtml = (tag) => {
                const node = item.querySelector(tag);
                if (!node) return '';
                if (node.firstChild && node.firstChild.nodeType === Node.CDATA_SECTION_NODE) { return node.firstChild.textContent.trim(); }
                return node.innerHTML.trim();
             };
            const masteryValue = parseFloat(get('mastery')) || 0;
            return `
                <div class="skill-card">
                    <div class="skill-info">
                        <div class="skill-header"><span class="skill-name">${get('name')}</span><span class="skill-type">${get('type')}</span></div>
                        <div class="card-stats-grid">
                            <span class="stat-label">Cảnh giới/Tầng</span><span>${get('level')}</span>
                            <span class="stat-label">Độ thuần thục</span>
                            <div class="progress-bg"><div class="progress-fill fill-exp" style="width: ${masteryValue}%;"></div></div>
                        </div>
                        <div class="skill-description">${getHtml('desc')}</div>
                    </div>
                </div>`;
        });
        renderList('partners > partner', '#tab-partners', item => {
            const get = (tag) => item.querySelector(tag)?.textContent.trim() || '';
            const getHtml = (tag) => {
                const node = item.querySelector(tag);
                if (!node) return '';
                if (node.firstChild && node.firstChild.nodeType === Node.CDATA_SECTION_NODE) { return node.firstChild.textContent.trim(); }
                return node.innerHTML.trim();
            };
            const loyalty = parseFloat(get('loyalty')) || 0;
            const hp = parseFloat(get('hp')) || 0;
            const mp = parseFloat(get('mp')) || 0;
            const personality = get('personality') || 'Chưa rõ';
            return `
                <div class="partner-card">
                    <div class="partner-info">
                        <div class="partner-header">
                            <div><span class="partner-name">${get('name')}</span><span class="partner-species">${get('species')}</span></div>
                            <span class="status-badge ${item.querySelector('status')?.getAttribute('class') || ''}">${get('status')}</span>
                        </div>
                        <div class="card-stats-grid">
                            <span class="stat-label">Sinh mệnh</span><div class="progress-bg"><div class="progress-fill fill-hp" style="width:${hp}%;"></div></div>
                            <span class="stat-label">Linh lực</span><div class="progress-bg"><div class="progress-fill fill-mp" style="width:${mp}%;"></div></div>
                            ${(loyalty > 0) ? `<span class="stat-label">Thân mật</span><div class="progress-bg"><div class="progress-fill fill-san" style="width:${loyalty}%;"></div></div>` : ''}
                            <span class="stat-label">Tính cách</span><div>${personality}</div>
                            <span class="stat-label">Thần thông</span><div>${getHtml('abilities')}</div>
                            <span class="stat-label">Tiếng lòng</span><div>${getHtml('thoughts')}</div>
                        </div>
                    </div>
                </div>`;
        });
        renderList('npcs > npc', '#tab-npcs', item => {
            const get = (tag) => item.querySelector(tag)?.textContent.trim() || '';
            const getHtml = (tag) => {
                const node = item.querySelector(tag);
                if (!node) return '';
                if (node.firstChild && node.firstChild.nodeType === Node.CDATA_SECTION_NODE) { return node.firstChild.textContent.trim(); }
                return node.innerHTML.trim();
            };
            const relation = parseFloat(get('relation')) || 0;
            const realm = get('realm');
            const hp = parseFloat(get('hp')) || 0;
            const mp = parseFloat(get('mp')) || 0;
            return `
                <div class="npc-card">
                    <div class="npc-info">
                        <div class="npc-header">
                            <span class="npc-name">${get('name')}</span>
                            <span class="npc-title ${item.querySelector('title')?.getAttribute('class') || ''}">${get('title')}</span>
                        </div>
                        <div class="card-stats-grid">
                            <span class="stat-label">Cảnh giới</span><span class="rare-text">${realm}</span>
                            <span class="stat-label">Sinh mệnh</span><div class="progress-bg"><div class="progress-fill fill-hp" style="width:${hp}%;"></div></div>
                            <span class="stat-label">Linh lực</span><div class="progress-bg"><div class="progress-fill fill-mp" style="width:${mp}%;"></div></div>
                            <span class="stat-label">Hảo cảm</span><div class="progress-bg"><div class="progress-fill ${relation > 50 ? 'fill-san' : 'fill-hp'}" style="width:${relation}%;"></div></div>
                        </div>
                        <div class="npc-description">${getHtml('desc')}</div>
                    </div>
                </div>`;
        });
        renderList('quests > quest', '#tab-quests', item => {
            const get = (tag) => item.querySelector(tag)?.textContent.trim() || '';
            const getHtml = (tag) => {
                const node = item.querySelector(tag);
                if (!node) return '';
                if (node.firstChild && node.firstChild.nodeType === Node.CDATA_SECTION_NODE) { return node.firstChild.textContent.trim(); }
                return node.innerHTML.trim();
            };
            return `
                <div class="quest-item">
                    <div class="info-title">
                        <span style="color:var(--text-main)">${get('title')}</span>
                        <span class="danger-text" style="font-size:0.8em">Độ khó: ${get('difficulty')}</span>
                    </div>
                    <div class="info-text">
                        <b>Mục tiêu:</b> ${getHtml('goal')}<br>
                        <b>Cơ duyên:</b> <span style="color:var(--accent-gold)">${get('reward')}</span><br>
                        <i style="font-size:0.8em; color:#999;">"${get('quote')}"</i>
                    </div>
                </div>`;
        });
    }
</script>
</body>
</html>
