                { id: 1, name: "Phàm Trần Thư Sinh", desc: "Một kẻ phàm nhân, tay trói gà không chặt, nhưng vô tình nhặt được di vật của tiên nhân, từ đó vận mệnh xoay chuyển.", data: { name: "Tô Văn", gender: "Nam", realm: "Phàm nhân", identity: "Thư sinh lạc phách", skills: "Đọc qua là nhớ, một miếng ngọc bội bí ẩn có thể hấp thu nguyệt hoa" }},
