            const allFortunePresets = [
                { name: "Thiên Mệnh Chi Tử", desc: "Gặp dữ hóa lành, kỳ ngộ liên tục, bình cảnh đối với ngươi mỏng như tờ giấy." }, { name: "Sát Thần Tái Thế", desc: "Càng chiến đấu, tu vi tăng càng nhanh, hơn nữa có thể cướp đoạt khí vận từ đối thủ." }, { name: "Đan Đạo Tông Sư", desc: "Luyện đan dễ như ăn cơm uống nước, cực ít thất bại, ngẫu nhiên có đan kiếp cũng có thể hóa thành của mình." }, { name: "Hồng Phúc Tề Thiên", desc: "Đi đường cũng nhặt được thiên tài địa bảo, tùy tiện vào một hang động cũng là động phủ của tu sĩ thượng cổ." }, { name: "Ách Vận Quấn Thân", desc: "Con đường tu hành đầy chông gai, thường gặp tâm ma, nhưng mỗi lần đột phá thực lực viễn siêu cùng cấp." }, { name: "Vạn Pháp Quy Nhất", desc: "Tu tập bất kỳ công pháp nào cũng nhanh chóng nắm bắt, dễ dàng suy một ra ba, dung hợp công pháp." }, { name: "Kiếm Tâm Thông Minh", desc: "Trời sinh phôi kiếm tu, kiếm đạo không bình cảnh, bất kỳ kiếm khí nào trong tay ngươi đều phát huy mười hai phần uy lực." }, { name: "Mị Hoặc Chúng Sinh", desc: "Mị lực siêu phàm, bất kể là người hay yêu, là tiên hay ma, đều dễ dàng nảy sinh hảo cảm với ngươi." }, { name: "Luân Hồi Chi Thân", desc: "Mang theo ký túc kiếp trước, thần hồn cường đại, tu hành sơ kỳ đã có thể vượt cấp khiêu chiến." }, { name: "Ngũ Hành Bất Toàn", desc: "Không thể tu tập công pháp ngũ hành, nhưng công pháp một hệ nào đó (như Lôi, Băng, Phong) uy lực tăng gấp bội." }, { name: "Khí Đạo Thánh Thủ", desc: "Trời sinh có lĩnh ngộ cực cao với luyện khí, có thể khiến phàm sắt cũng tỏa ra bảo quang." }, { name: "Trận Pháp Đại Sư", desc: "Có sự thân hòa tự nhiên với trận văn thiên địa, không thầy cũng tự thông các loại sát trận, huyễn trận." }, { name: "Thú Ngữ Giả", desc: "Có thể giao tiếp với linh thú thậm chí hung thú, dễ dàng thu được sự đi theo của thú sủng cường đại." }, { name: "Thiên Sinh Độc Thể", desc: "Bách độc bất xâm, lại có thể hóa kịch độc thành tu vi bản thân, là ác mộng của tu sĩ ma đạo." }, { name: "Ngôn Xuất Pháp Tùy", desc: "Thỉnh thoảng lời nói ra sẽ thành hiện thực, nhưng đa phần là việc nhỏ không quan trọng." }, { name: "Thiên Đố Anh Tài", desc: "Tốc độ tu hành gấp mấy lần thường nhân, nhưng mỗi lần đại cảnh giới đột phá tất dẫn tới thiên kiếp khủng bố viễn siêu cùng cấp." }, { name: "Phàm Nhân Trí Tuệ", desc: "Linh căn tư chất bình thường, nhưng tâm trí siêu quần, am hiểu lấy yếu thắng mạnh, bố cục tính toán." }, { name: "Nghèo Rớt Mồng Tơi", desc: "Trời sinh vô duyên với linh thạch, bất kể có bao nhiêu tài phú đều sẽ rất nhanh tiêu hết một cách khó hiểu." }, { name: "Vạn Người Ghét", desc: "Không biết vì sao, luôn dễ dàng khiến người khác ác cảm cùng thù địch." }, { name: "Mù Đường", desc: "Cho dù có bản đồ cũng sẽ lạc đường, nhưng cũng vì vậy mà thường thường đi nhầm vào bí cảnh." }, { name: "Đào Hoa Kiếp", desc: "Một đời tình lộ gập ghềnh, gặp phải đều là nghiệt duyên, cắt không đứt, gỡ càng rối." }, { name: "Thiên Sát Cô Tinh", desc: "Khắc thân khắc bạn, người thân cận bên cạnh luôn gặp bất hạnh." }, { name: "Nói Nhiều", desc: "Không thể khống chế dục vọng nói chuyện của mình, thường thường vì vậy mà tiết lộ bí mật hoặc đắc tội người khác." }, { name: "Thực Thần", desc: "Có sự theo đuổi vô tận với mỹ thực, nuốt thiên tài địa bảo có thể đạt được hiệu quả gấp đôi, nhưng luôn cảm thấy đói khát." }, { name: "Thánh Ngủ", desc: "Hơi một tí là chìm vào giấc ngủ, một giấc ngủ liền vài tháng thậm chí vài năm, sau khi tỉnh lại tu vi sẽ tăng trưởng nhỏ." }, { name: "Mộng Trung Chứng Đạo", desc: "Trong mộng cảnh có thể diễn toán công pháp, thậm chí giao lưu với đại năng cổ đại, nhưng sau khi tỉnh lại ký ức mơ hồ." }, { name: "Lão Gia Gia Phụ Thể", desc: "Trên người ngươi ký túc một tàn hồn thần bí, lúc thì chỉ điểm ngươi, lúc thì đào hố cho ngươi." }, { name: "Huyết Mạch Phản Tổ", desc: "Mang trong mình huyết mạch thần ma thượng cổ, sẽ thức tỉnh trong điều kiện đặc thù, đạt được sức mạnh cường đại, nhưng có thể mất đi lý trí." }, { name: "Nhân Vật Chính (Giả)", desc: "Luôn tưởng mình là con cưng của trời, thích khắp nơi gây chuyện thị phi, nhưng lại không có vận khí của nhân vật chính." }, { name: "Người Bàng Quan", desc: "Ngươi luôn có thể chứng kiến các sự kiện lịch sử trọng đại phát sinh, nhưng bản thân thủy chung chỉ là một người đứng xem." }, { name: "Vạn Bảo Chi Thể", desc: "Thân thể ngươi có lực hấp dẫn chí mạng với pháp bảo, pháp bảo sẽ tự động nhận ngươi làm chủ, nhưng cũng dễ bị tu sĩ cấp cao nhớ thương." }, { name: "Vận Rủi Chia Sẻ", desc: "Kẻ địch của ngươi sẽ mạc danh kỳ diệu gặp phải đủ loại chuyện xui xẻo." }, { name: "Nhân Quả Nghịch Chuyển", desc: "Thương tổn nhận phải có tỷ lệ nhất định chuyển dời lên người tấn công." }, { name: "Con Cưng Thời Gian", desc: "Cảm nhận đối với dòng chảy thời gian khác với thường nhân, khi tu luyện hoặc cảm ngộ thời gian trôi chậm lại." }, { name: "Không Gian Hành Giả", desc: "Có trực giác nhạy bén với không gian, dễ dàng lĩnh ngộ thần thông không gian, chạy trốn đệ nhất. "}, { name: "Kẻ Mô Phỏng", desc: "Có thể mô phỏng hoàn mỹ và sử dụng một lần bất kỳ thần thông phi huyết mạch nào ngươi từng thấy, sau đó liền sẽ quên mất." }, { name: "Điểm Đá Thành Vàng", desc: "Linh lực của ngươi chạm vào phàm vật, có xác suất cực nhỏ khiến nó lột xác thành linh vật." }, { name: "Thảo Mộc Thân Hòa", desc: "Tất cả sinh linh thực vật đều vui vẻ thân cận ngươi, linh dược ngàn năm ở bên cạnh ngươi cũng sẽ lớn nhanh hơn." }, { name: "Thư Trung Tiên", desc: "Có thể từ bất kỳ điển tịch nào hấp thu linh khí yếu ớt hoặc cảm ngộ, đọc sách chính là tu hành." }, { name: "Nghịch Tri Tương Lai", desc: "Thỉnh thoảng có thể nhìn thấy những đoạn ngắn liên quan đến mình trong một canh giờ tới, nhưng nhìn thấy đều là chuyện xấu." }, { name: "Tiểu Cường Bất Tử", desc: "Sinh mệnh lực cực kỳ ngoan cường, bất luận thương thế nặng bao nhiêu, chỉ cần còn một hơi thở là có thể từ từ khôi phục." }, { name: "Tài Khả Thông Thần", desc: "Tiêu phí linh thạch có thể tăng nhanh tốc độ tu luyện, linh thạch càng nhiều, tu luyện càng nhanh." }, { name: "Trộm Thiên Đổi Nhật", desc: "Am hiểu ẩn nấp và ngụy trang, hầu như không ai có thể nhìn thấu tu vi chân thật và thân phận của ngươi." }, { name: "Song Sinh Hồn", desc: "Ngươi sở hữu hai linh hồn, có thể nhất tâm nhị dụng, thần hồn công kích đối với ngươi hiệu quả giảm phân nửa." }, { name: "Vấn Đạo Chi Tâm", desc: "Đạo tâm của ngươi vô cùng kiên định, không dễ sinh ra tâm ma, huyễn thuật đối với ngươi hầu như vô hiệu." }, { name: "Phá Pháp Chi Nhãn", desc: "Có thể dễ dàng nhìn thấu điểm yếu của đại bộ phận trận pháp và cấm chế." }, { name: "Vô Cấu Chi Thể", desc: "Thân thể tinh khiết không tì vết, tốc độ tu luyện gấp đôi thường nhân, hơn nữa sẽ không có bình cảnh." }, { name: "Tiên Thiên Đạo Thai", desc: "Trời sinh tương hợp với đại đạo, lĩnh ngộ công pháp thần thông làm ít công to." }, { name: "Thái Thượng Vong Tình", desc: "Tình cảm đạm mạc, không dễ bị ngoại vật lay động, là nhân tuyển tuyệt hảo tu luyện Vô Tình Đạo." }, { name: "Âm Dương Thánh Thể", desc: "Có thể điều hòa hai khí âm dương, tu luyện bất kỳ công pháp thuộc tính nào cũng sẽ không xung đột." }, { name: "Ngũ Hành Linh Thể", desc: "Ngũ hành cân bằng, có thể đồng thời tu luyện ngũ hành công pháp, tương sinh tương khắc, uy lực vô cùng." }, { name: "Hỗn Độn Thể", desc: "Thể chất trong truyền thuyết, có thể dung nạp hết thảy lực lượng, tiềm lực vô hạn, nhưng trưởng thành chậm chạp." }, { name: "Tai Ách Chi Nguyên", desc: "Ngươi đi đến đâu, tai nạn theo đến đó, nhưng ngươi luôn có thể may mắn thoát nạn." }, { name: "Phúc Duyên Thâm Hậu", desc: "Ra cửa luôn có thể gặp quý nhân tương trợ, hóa hiểm thành di." }, { name: "Thiên Sinh Phật Tử", desc: "Có duyên với Phật, dễ dàng lĩnh ngộ Phật pháp thần thông, yêu ma quỷ quái thấy ngươi lui tránh ba xá." }, { name: "Ma Tâm Chủng Đạo", desc: "Lấy ma tính tẩm bổ đạo tâm, giết chóc càng nhiều, đạo tâm càng là vững chắc." }, { name: "Họa Địa Vi Lao", desc: "Một khi quyết định bế quan, không đột phá tuyệt không xuất quan, trong lúc đó không chịu bất kỳ quấy nhiễu nào." }, { name: "Đổ Đồ", desc: "Cuộc đời ngươi chính là một ván cược lớn, ngươi luôn thích đánh cược tất cả vào thời khắc mấu chốt." }, { name: "Văn Vận Gia Thân", desc: "Thi từ văn chương ngươi viết ra ẩn chứa đạo vận, có thể dẫn động thiên địa dị tượng." }, { name: "Thiên Âm Cộng Hưởng", desc: "Tiếng hát hoặc tiếng đàn của ngươi có thể dẫn động thiên địa linh khí, hỗ trợ tu luyện hoặc công kích kẻ địch."}, { name: "Bách Thảo Chi Thể", desc: "Có khả năng nhận biết tự nhiên với tất cả linh thảo, có thể dễ dàng phát hiện linh dược ẩn tàng." }, { name: "Trận Đạo Thiên Thành", desc: "Bày trận dễ như trở bàn tay, có thể dùng tài liệu đơn sơ bố hạ trận pháp uy lực không tầm thường." }, { name: "Khôi Lỗi Chi Tâm", desc: "Có thiên phú cực cao với thuật khôi lỗi, có thể cùng khôi lỗi của mình sinh ra liên hệ tâm thần." }, { name: "Thần Hành Thái Bảo", desc: "Trời sinh chạy nhanh, tốc độ tu luyện thần thông loại thân pháp tăng gấp đôi." }, { name: "Độn Cảm Chi Khu", desc: "Không mẫn cảm với đau đớn, trên con đường thể tu có thể chịu đựng càng nhiều thống khổ, đi được càng xa." }, { name: "Sưu Bảo Thử", desc: "Cực kỳ mẫn cảm với khí tức bảo vật, luôn có thể tìm được bảo vật trong bí cảnh trước người khác một bước." }, { name: "Kết Bạn Khắp Thiên Hạ", desc: "Bất luận đi đến đâu, đều có thể dễ dàng kết giao bằng hữu, đạt được trợ giúp." }, { name: "Người Cô Tịch", desc: "Không giỏi giao tế với người khác, nhưng khi một mình, hiệu suất tu luyện và cảm ngộ tăng lên." }, { name: "Cần Cù Bù Thông Minh", desc: "Tư chất tuy rằng bình thường, nhưng nghị lực kinh người, chỉ cần bỏ thời gian, bất kỳ công pháp nào cũng có thể luyện thành." }, { name: "Tửu Kiếm Tiên (Giả)", desc: "Mê rượu như mạng, uống càng nhiều, kiếm pháp càng lăng lệ, nhưng thần trí không rõ." }, { name: "Nhất Nặc Thiên Kim", desc: "Lời hứa của ngươi có lực lượng kỳ dị, một khi hứa hẹn, nhất định phải hoàn thành, nếu không sẽ bị thiên đạo phản phệ." }, { name: "Nhạc Thiện Hảo Thi", desc: "Giúp đỡ người khác sẽ khiến ngươi đạt được công đức kim quang hộ thể, tăng lên khí vận." }, { name: "Tính Toán Chi Li", desc: "Đối với bất kỳ tài nguyên nào cũng tính toán tỉ mỉ, chưa bao giờ lãng phí, nhưng cũng vì thế mà có vẻ keo kiệt." }, { name: "Trù Thần Chi Tâm", desc: "Chế tác thức ăn không chỉ là mỹ vị, càng có thể trở thành linh thực ẩn chứa linh khí." }, { name: "Miệng Quạ Đen", desc: "Ngươi vô tâm nói ra lời xấu, có xác suất rất lớn sẽ ứng nghiệm lên chính mình hoặc đồng bạn." }, { name: "Giả Ngầu Như Gió", desc: "Ngươi luôn có thể xuất hiện với tư thái tiêu sái nhất vào thời khắc mấu chốt, chấn nhiếp kẻ địch, nhưng cũng dễ trở thành mục tiêu công kích." }, { name: "Khắc Tinh Phản Diện", desc: "Ngươi dường như trời sinh chính là khắc tinh của nhân vật phản diện, luôn có thể phát hiện sơ hở trong các loại âm mưu." }, { name: "Linh Thạch Tuyệt Duyên Thể", desc: "Linh thạch trong tay ngươi sẽ gia tốc linh khí xói mòn, không thể dùng để tu luyện." }, { name: "Kẻ Hủy Diệt Bí Cảnh", desc: "Bất kỳ bí cảnh hoặc di tích nào ngươi tiến vào, đều có xác suất cực lớn sụp đổ sau khi ngươi rời đi." }, { name: "Sư Tôn Mẫu Mực", desc: "Ngươi rất dễ nhặt được đồ đệ tư chất tuyệt hảo, nhưng bọn hắn cũng luôn sẽ gây cho ngươi phiền toái lớn." }, { name: "Đoạt Bảo Kỳ Binh", desc: "Ngươi am hiểu cướp đoạt bảo vật từ trong tay người khác, nhưng cũng sẽ vì thế kết hạ vô số cừu gia." }, { name: "Người Bị Lãng Quên", desc: "Ngươi rất dễ bị người khác quên đi, cho dù vừa mới gặp mặt, quay đầu liền không còn ấn tượng, là nhân tuyển tuyệt hảo làm ám thám." }, { name: "Cổ Thần Huyết Duệ", desc: "Trong cơ thể chảy xuôi máu Cổ Thần loãng, ở một vài hoàn cảnh đặc thù có thể bộc phát ra lực lượng kinh người." }, { name: "Họa Sư Thiên Bẩm", desc: "Thứ ngươi vẽ ra có xác suất ngắn ngủi hóa thành tồn tại chân thật." }, { name: "Thiên Tài Thuần Thú", desc: "Bất kỳ yêu thú nào trước mặt ngươi đều sẽ trở nên ôn thuận, dễ dàng bị ngươi thuần phục." }, { name: "Lôi Linh Chi Thể", desc: "Không sợ sấm sét, tu luyện lôi hệ công pháp uy lực cực lớn, khi độ kiếp uy lực lôi kiếp giảm phân nửa." }, { name: "Băng Cơ Ngọc Cốt", desc: "Trời sinh thích hợp tu luyện băng hệ công pháp, dung nhan không già, khí chất thanh lãnh." }, { name: "Đa Trọng Nhân Cách", desc: "Trong cơ thể ngươi ở nhiều nhân cách khác nhau, bọn họ có lẽ sở hữu năng lực và tri thức khác nhau." }, { name: "Hậu Phát Chế Nhân", desc: "Phản kích của ngươi luôn mạnh mẽ hơn so với chủ động công kích." }, { name: "Thiên Đạo Thù Cần", desc: "Chỉ cần kiên trì tu luyện, cho dù không có kỳ ngộ, tu vi cũng sẽ vững bước tăng trưởng, từ không có bình cảnh." }, { name: "Thánh Mẫu Chi Tâm", desc: "Ngươi không cách nào thấy chết không cứu đối với bất luận kẻ nào, cho dù đối phương là kẻ địch của ngươi." }, { name: "Vắt Cổ Chày Ra Nước", desc: "Coi tiền như mạng, muốn từ trên người ngươi lấy đi một hào một cắc đều khó như lên trời." }, { name: "Kẻ Nói Dối", desc: "Lời nói dối ngươi nói ra không ai có thể phân biệt thật giả, nhưng khi ngươi nói thật lại không ai tin tưởng." }, { name: "Kẻ Xui Xẻo", desc: "Chuyện tốt không tới lượt ngươi, chuyện xấu luôn có một phần của ngươi." }, { name: "Người Làm Nền", desc: "Cho dù thân ở trung tâm sự kiện lớn, ngươi cũng luôn là người không có cảm giác tồn tại nhất." }, { name: "Gương Vỡ Lại Lành", desc: "Bất kỳ pháp bảo hoặc khí cụ rách nát nào, ở trong tay ngươi đều có xác suất được chữa trị." }, { name: "Xe Đạp Công Cộng", desc: "Thân thể của ngươi rất dễ dàng bị linh hồn khác chiếm cứ hoặc đoạt xá." }, { name: "Ninja Sao Chép", desc: "Có thể sao chép thần thông dùng một lần đối phương từng sử dụng, nhưng uy lực chỉ có một nửa nguyên tác." }, { name: "Người Theo Chủ Nghĩa Hòa Bình", desc: "Ngươi chán ghét chiến đấu, người ở bên cạnh ngươi, dục vọng chiến đấu sẽ hạ thấp." }, { name: "Kẻ Kết Thúc", desc: "Bất kỳ câu chuyện nào đến chỗ ngươi, dường như đều nghênh đón chương cuối." }
            ];

            function createPresetButtons(container, presetsData, clickHandler) {
                container.innerHTML = ''; 
                presetsData.forEach((preset, index) => {
                    const btn = document.createElement('button');
                    btn.className = 'preset-btn';
                    btn.textContent = preset.name;
                    btn.dataset.id = index;
                    btn.title = preset.desc;
                    container.appendChild(btn);
                });
                container.addEventListener('click', clickHandler);
            }

            createPresetButtons(presetButtonsContainer, presets, (e) => {
                if (e.target.classList.contains('preset-btn')) {
                    document.querySelectorAll('#preset-buttons .preset-btn').forEach(btn => btn.classList.remove('selected'));
                    e.target.classList.add('selected');

                    const presetId = parseInt(e.target.dataset.id);
                    const selectedPreset = presets.find(p => p.id === presetId).data;

                    nameInput.value = selectedPreset.name;
                    genderSelect.value = selectedPreset.gender;
                    realmInput.value = selectedPreset.realm;
                    identityInput.value = selectedPreset.identity;
                    skillsTextarea.value = selectedPreset.skills;
                }
            });

            drawFortuneBtn.addEventListener('click', () => {
                drawFortuneBtn.textContent = 'Đang diễn toán...';
                drawFortuneBtn.disabled = true;

                setTimeout(() => {
                    const randomIndex = Math.floor(Math.random() * allFortunePresets.length);
                    const randomFortune = allFortunePresets[randomIndex];

                    fortuneNameDisplay.textContent = `【${randomFortune.name}】`;
                    fortuneInput.value = randomFortune.desc;

                    drawFortuneBtn.textContent = 'Tính lại lần nữa';
                    drawFortuneBtn.disabled = false;
                }, 800);
            });

            const particleContainer = document.getElementById('background-particles');
            const numParticles = 40;
            for (let i = 0; i < numParticles; i++) {
                let particle = document.createElement('div');
                particle.className = 'particle';
                let size = Math.random() * 4 + 1.5;
                particle.style.width = `${size}px`;
                particle.style.height = `${size}px`;
                particle.style.left = `${Math.random() * 100}%`;
                particle.style.animationDelay = `${Math.random() * 25}s`;
                particle.style.animationDuration = `${Math.random() * 20 + 15}s`;
                if(Math.random() > 0.8) {
                    particle.style.backgroundColor = 'var(--gold-color)';
                     particle.style.boxShadow = '0 0 8px var(--gold-color)';
                }
                particleContainer.appendChild(particle);
            }

            function transitionToCreation(mode) {
                if (mode === 'normal') {
                    customFortuneSection.style.display = 'none';
                    companionSection.style.display = 'none';
                } else {
                    customFortuneSection.style.display = 'block';
                    companionSection.style.display = 'block';
                }

                initialView.style.display = 'none'; 

                startScreen.classList.remove('active');
                setTimeout(() => creationScreen.classList.add('active'), 300);
            }

            startButton.addEventListener('click', () => {
                initialView.style.display = 'none';

                modeSelection.classList.add('visible');
            });

            simpleModeBtn.addEventListener('click', () => transitionToCreation('simple'));
            normalModeBtn.addEventListener('click', () => transitionToCreation('normal'));

            confirmButton.addEventListener('click', () => {
                const customFortuneName = customFortuneNameInput.value.trim();
                const customFortuneDesc = customFortuneDescTextarea.value.trim();

                let finalFortuneName, finalFortuneDesc;

                if (customFortuneName || customFortuneDesc) {
                    finalFortuneName = customFortuneName;
                    finalFortuneDesc = customFortuneDesc;
                } else {
                    finalFortuneName = fortuneNameDisplay.textContent.trim().replace(/【|】/g, '');
                    finalFortuneDesc = fortuneInput.value.trim();
                }

                let combinedFortune = finalFortuneName ? `【${finalFortuneName}】 ${finalFortuneDesc}` : finalFortuneDesc;
                if (!combinedFortune.trim()) {
                    combinedFortune = 'Vô';
                }

                const characterData = {
                    name: nameInput.value.trim(),
                    gender: genderSelect.value,
                    realm: realmInput.value.trim(),
                    identity: identityInput.value.trim(),
                    skills: skillsTextarea.value.trim(),
                    fortune: combinedFortune
                };

                const companionData = {
                    name: companionNameInput.value.trim(),
                    race: companionRaceInput.value.trim(),
                    class: companionClassInput.value.trim(),
                    personality: companionPersonalityInput.value.trim(),
                    age: companionAgeInput.value.trim(),
                    abilities: companionAbilitiesTextarea.value.trim(),
                    backstory: companionBackstoryTextarea.value.trim()
                };

                if (!characterData.name) {
                    nameInput.style.borderColor = 'var(--accent-blue)';
                    nameInput.placeholder = 'Đạo hiệu không được để trống!';
                    setTimeout(() => {
                       nameInput.style.borderColor = 'var(--input-border)';
                       nameInput.placeholder = 'Tên thật hoặc đạo hiệu của bạn';
                    }, 2000);
                    return;
                }

                document.body.innerHTML = '<div style="display:flex; justify-content:center; align-items:center; height:100vh;"><h1 class="title" style="animation: none; opacity: 1;">...Tiên Đồ Đã Mở...</h1></div>';

                let sysMessage = `/sys [Tiên Duyên Đã Định]\n**Đạo hiệu**: ${characterData.name}\n**Giới tính**: ${characterData.gender}\n**Cảnh giới**: ${characterData.realm || 'Phàm nhân'}\n**Xuất thân**: ${characterData.identity}\n**Linh căn/Công pháp**: ${characterData.skills}\n**Khí vận**: ${characterData.fortune}`;

                if (companionSection.style.display !== 'none' && companionData.name) {
                    sysMessage += `\n\n[Thiên Định Đạo Lữ]\n**Họ Tên**: ${companionData.name}\n**Chủng tộc/Thân phận**: ${companionData.race}\n**Cảnh giới/Tu vi**: ${companionData.class}\n**Tính tình**: ${companionData.personality}\n**Tuổi tác**: ${companionData.age}\n**Công pháp/Năng lực**: ${companionData.abilities}\n**Mối Duyên Với Bạn**: ${companionData.backstory}`;
                }

                sysMessage += `\n\n[Tiên Đồ Khai Mở...]`;

                const startCommand = `${sysMessage} | /trigger`;

                if (typeof triggerSlash === 'function' && typeof getCurrentMessageId === 'function') {
                    triggerSlash(startCommand);
                    const currentMessageId = getCurrentMessageId();
                    setTimeout(() => {
                        triggerSlash(`/cut ${currentMessageId}`);
                    }, 1500);
                } else {
                    console.log("Không thể kích hoạt lệnh SillyTavern, đây là lệnh đã tạo:", startCommand);
                    alert("Tiên duyên đã định! Vui lòng sử dụng trong môi trường SillyTavern để tự động gửi tin nhắn.");
                }
            });
        });
    </script>
</body>
</html>
```
